scwin.onpageload = function () {
  ed_lineCd.setValue("SITC");
  ed_txt_lineNm.setValue("SITC CONTAINER LINES CO.,LTD.");
  $c.gus.cfDisableObjects($p, [ed_lineCd]);
  $c.gus.cfDisableObjects($p, [ed_txt_lineNm]);
  $c.gus.cfDisableObjects($p, tb_retrieveData);
  $c.gus.cfDisableBtn($p, [btn_updateBatch, btn_update, btn_save]);

  //ed_lineCd.index = 0;
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  cal_doIssueDdDt.setInitDate(scwin.vCurDate, scwin.vCurDate);
  scwin.initComp();
};
scwin.initComp = function () {
  var codeObj = [ed_vsslCd];
  for (var i = 0; i < codeObj.length; i++) {
    codeObj[i].unbind('onkeyup');
    codeObj[i].bind('onkeyup', function (e) {
      var obj = window[e.target.id];
      if (obj && obj.getValue) {
        var oldVal = obj._oldValue;
        var newVal = obj.getValue().toUpperCase();
        obj.setValue(newVal);
        obj._oldValue = oldVal;
      }
    });
  }
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
  $c.gus.cfInitObjects($p, tb_queryList, null);
  ed_lineCd.setValue("SITC");
  ed_txt_lineNm.setValue("SITC CONTAINER LINES CO.,LTD.");
  cal_doIssueDdDt.setInitDate(scwin.vCurDate, scwin.vCurDate);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = async function (e) {
  let rtn1 = await $c.gus.cfValidate($p, [tb_queryList]);
  if (!rtn1) {
    return;
  }
  if (!$c.gus.cfValidate($p, doIssueDdStDt) || !$c.gus.cfValidate($p, doIssueDdEndDt)) {
    return;
  }
  var afterDate = $c.gus.cfIsAfterDate($p, doIssueDdStDt.getValue(), doIssueDdEndDt.getValue());
  if (!afterDate) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    doIssueDdStDt.focus();
    return;
  }
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    //HeadCheck 초기화
    //gr_list.ColumnProp('chk', 'HeadCheck') = "false";

    //일괄수정 외 일때 HeadCheckShow 히든처리
    //gr_list.ColumnProp('chk', 'HeadCheckShow') = false;

    let allData = ds_list.getAllJSON();
    for (let i = 0; i < allData.length; i++) {
      rowData = allData[i];
      if (rowData["gateOutDtm"].length == 0 && rowData["gateInDtm"].length == 0) {
        ds_list.setCellData(i, "gateOutDtm", null);
        ds_list.setCellData(i, "gateInDtm", null);
      }
      if (rowData["gateOutDtm"].length > 0 && rowData["gateInDtm"].length == 0) {
        ds_list.setCellData(i, "gateOutDtm", rowData["gateOutDtm"].substring(0, 4) + "/" + rowData["gateOutDtm"].substring(4, 6) + "/" + rowData["gateOutDtm"].substring(6, 8));
        ds_list.setCellData(i, "gateInDtm", null);
      } else if (rowData["gateOutDtm"].length == 0 && rowData["gateInDtm"].length > 0) {
        ds_list.setCellData(i, "gateOutDtm", null);
        ds_list.setCellData(i, "gateInDtm", rowData["gateInDtm"].substring(0, 4) + "/" + rowData["gateInDtm"].substring(4, 6) + "/" + rowData["gateInDtm"].substring(6, 8));
      } else if (rowData["gateOutDtm"].length > 0 && rowData["gateInDtm"].length > 0) {
        ds_list.setCellData(i, "gateOutDtm", rowData["gateOutDtm"].substring(0, 4) + "/" + rowData["gateOutDtm"].substring(4, 6) + "/" + rowData["gateOutDtm"].substring(6, 8));
        ds_list.setCellData(i, "gateInDtm", rowData["gateInDtm"].substring(0, 4) + "/" + rowData["gateInDtm"].substring(4, 6) + "/" + rowData["gateInDtm"].substring(6, 8));
      }
    }
    ;
    totalRows.setValue(ds_list.getRowCount());

    //조회결과가 0인경우
    if (ds_list.getRowCount() == 0) {
      $c.gus.cfDisableBtn($p, [btn_updateBatch, btn_update, btn_save]);
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_003); //("조회결과가 존재하지 않습니다.");
      return;
    } else {
      $c.gus.cfDisableBtn($p, [btn_save]);
      $c.gus.cfEnableBtnOnly($p, [btn_updateBatch, btn_update]);
    }

    //기존행 포커스
    gr_list.setFocusedCell(scwin.pos_rowSts, 0);

    //선택, 반출일자, 반납기한 수정불가능
    scwin.f_initEditable("N");
  }
};

//-------------------------------------------------------------------------
// 컬럼 수정여부 초기화
//-------------------------------------------------------------------------
scwin.f_initEditable = function (gubun) {
  switch (gubun) {
    case "Y":
      //일괄수정일때 HeadCheckShow 보여줌
      //gr_list.ColumnProp('chk', 'HeadCheckShow') = true;
      //gr_list.ColumnProp('chk', 'Edit') = "any";
      gr_list.removeHeaderClass("column1", "dis-none");
      //gr_list.setColumnDisabled("chk", false);
      gr_list.setColumnReadOnly("chk", false);

      //컬럼EDIT설정(반출기한, 반납기한)
      //gr_list.ColumnProp('cntrCrryoutCloseDt', 'Edit') = 'Numeric';
      //gr_list.ColumnProp('cntrRtrnDt', 'Edit') = 'Numeric';
      gr_list.setColumnReadOnly("cntrCrryoutCloseDt", false);
      gr_list.setColumnReadOnly("cntrRtrnDt", false);
      break;
    case "N":
      //일괄수정 외 일때 HeadCheckShow 가려줌
      //gr_list.ColumnProp('chk', 'HeadCheckShow') = false;
      //gr_list.ColumnProp('chk', 'Edit') = "none";
      gr_list.setHeaderClass("column1", "dis-none");
      //gr_list.setColumnDisabled("chk", true);
      gr_list.setColumnReadOnly("chk", true);

      //컬럼EDIT설정(반출기한, 반납기한)
      //gr_list.ColumnProp('cntrCrryoutCloseDt', 'Edit') = 'none';
      //gr_list.ColumnProp('cntrRtrnDt', 'Edit') = 'none';
      gr_list.setColumnReadOnly("cntrCrryoutCloseDt", true);
      gr_list.setColumnReadOnly("cntrRtrnDt", true);
      break;
  }
};

