  //SQL SELECT ID;
  pCode,
  //조회조건 CODE;
  pName,
  //조회조건 CODE_NAME;
  pClose,
  //1건일경우 자동 닫기 여부(T:자동닫기, F:보여주기);
  null, null, "120,200,0,0,0,0,0,0,0,0", null, null,
