scwin.btn_updateBatch_onclick = function (e) {
  scwin.tr_actionKind = "UPDATE";
  scwin.isBatch = 1;

  //선택, 반출일자, 반납기한 수정가능
  scwin.f_initEditable("Y");

  //버튼제어
  $c.gus.cfEnableBtnOnly($p, [btn_save]);
  $c.gus.cfDisableBtn($p, [btn_update, btn_updateBatch]);
};

