scwin.btn_update_onclick = function (e) {
  scwin.tr_actionKind = "UPDATE";
  scwin.updBtnYn = true;
  scwin.isBatch = 0;
  $c.gus.cfEnableObjects($p, [ica_ed_cntrCrryoutCloseDt, ica_ed_cntrRtrnDt]);

  //반납지가 있는 경우에만 수정가능하도록
  if (ed_arvWrkPlCd.getValue() != "") {
    $c.gus.cfEnableObjects($p, [ed_arvWrkPlCd, txt_arvWrkPlNm, btn_arvWrkPlCd]);
    //반납지를 필수항목으로
    scwin.f_mandatoryChange(1);
  }

  //버튼제어
  $c.gus.cfEnableBtnOnly($p, [btn_save]);
  $c.gus.cfDisableBtn($p, [btn_update, btn_updateBatch]);
};

