// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
  //현재 행저장
  scwin.pos_rowSts = ds_list.getRowPosition();
  var vRowStatus = ds_list.getRowStatusValue(ds_list.getRowPosition());
  if (vRowStatus == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, new Array("컨테이너 진행현황"));
    return false;
  }
  var chkCnt = 0; //체크수
  for (var i = 0; i < ds_list.getRowCount(); i++) {
    if (ds_list.getCellData(i, "chk") == 1) {
      chkCnt++;
    }
    if (ds_list.getCellData(i, "chk") == 1 && ds_list.getCellData(i, "cntrCrryoutCloseDt") == null || ds_list.getCellData(i, "chk") == 1 && ds_list.getCellData(i, "cntrCrryoutCloseDt") == "") {
      $c.win.alert($p, "반출기한은(는) 필수 입력 항목입니다.");
      return false;
    }
    if (ds_list.getCellData(i, "chk") == 1 && ds_list.getCellData(i, "cntrCrryoutCloseDt").length != 8) {
      $c.win.alert($p, "반출기한은(는) 8자리수만큼 입력하십시오.");
      return false;
    }
  }
  if (scwin.isBatch == 1) {
    if (chkCnt == 0) {
      $c.win.alert($p, "선택된 행이 없습니다. 저장하려는 데이터를 선택하세요.");
      return false;
    }
  }
  if (ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt") == null || ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt") == "") {
    $c.win.alert($p, "반출기한은(는) 필수 입력 항목입니다.");
    return false;
  }
  if (ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt").length != 8) {
    $c.win.alert($p, "반출기한은(는) 8자리수만큼 입력하십시오.");
    return false;
  }

  //Mandatory 항목이 누락하지 않았는지 체크한다.
  let ret1 = await $c.gus.cfValidate($p, [tb_retrieveData]);
  if (!ret1) {
    return;
  }
  let ret2 = await $c.gus.cfValidate($p, ica_ed_cntrCrryoutCloseDt);
  if (!ret2) {
    return;
  }
  let confirm = await $c.win.confirm($p, "저장하시겠습니까?");
  if (confirm) {
    scwin.isBatch = "";
    //수정 + 저장
    dma_list.set("cntrCrryoutCloseDt", ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt"));
    dma_list.set("cntrRtrnDt", ds_list.getCellData(ds_list.getRowPosition(), "cntrRtrnDt"));
    dma_list.set("arvWrkPlCd", ds_list.getCellData(ds_list.getRowPosition(), "arvWrkPlCd"));

    //저장
    dma_list.set("doNo", ds_list.getCellData(ds_list.getRowPosition(), "doNo"));
    dma_list.set("blNo", ds_list.getCellData(ds_list.getRowPosition(), "blNo"));
    dma_list.set("doIssueDd", ica_ed_doIssueDd.getValue());
    dma_list.set("copinoId", ed_copinoId2.getValue());
    dma_list.set("callsignCd", ed_txt_callsignCd.getValue().toUpperCase());
    dma_list.set("vsslNm", ed_txt_vsslNm2.getValue().toUpperCase());
    dma_list.set("vsslPortcnt", ed_txt_vsslPortcnt.getValue().toUpperCase());
    dma_list.set("vsslArrvlportDtm", ica_ed_vsslArrvlportDtm.getValue());
    dma_list.set("cntrNo", ed_cntrNo2.getValue());
    dma_list.set("cntrNrm", ed_txt_cntrNrm.getValue().toUpperCase());
    dma_list.set("mrn", ed_txt_mrn.getValue().toUpperCase());
    dma_list.set("msn", ed_txt_msn.getValue());
    dma_list.set("dsmbrkPlcCd", ds_list.getCellData(ds_list.getRowPosition(), "dsmbrkPlcCd").toUpperCase());
    dma_list.set("dropPort", ed_txt_dropPort.getValue().toUpperCase());
    dma_list.set("dchrPort", ed_txt_dchrPort.getValue().toUpperCase());
    dma_list.set("sendMchtNm1", ed_txt_sendMchtNm1.getValue().toUpperCase());
    dma_list.set("cntMchtNm", ed_txt_cntMchtNm.getValue().toUpperCase());
    dma_list.set("rmkDesc", ed_txt_rmkDesc.getValue());
    if (scwin.tr_actionKind == "INSERT") {
      $c.sbm.execute($p, sbm_insert);
    } else if (scwin.tr_actionKind == "UPDATE") {
      $c.sbm.execute($p, sbm_update);
    }
  }
};
scwin.sbm_update_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    $c.gus.cfDisableObjects($p, tb_retrieveData);
    scwin.btn_retrieve_onclick();
  }
};
scwin.sbm_insert_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    $c.gus.cfDisableObjects($p, tb_retrieveData);
    scwin.btn_retrieve_onclick();
  }
};
scwin.gr_list_onheaderclick = function (headerId) {
  var cr = ds_list.getRowCount();
  //행이 0보다 크고, B/L, CNTR_NO항목이 NULL이 아닐 경우에만 체크 가능
  var check = gr_list.getHeaderValue("column1");
  if (cr > 0) {
    if (headerId == "column1" && check == 1) {
      for (var i = 0; i < cr; i++) {
        if (ds_list.getCellData(i, "blNo") != "" && ds_list.getCellData(i, "cntrNo") != "") {
          ds_list.setCellData(i, "chk", 1);
          //상태를 UPDATE로 변경한다.
          ds_list.modifyRowStatus(i, "U"); //UPDATE(3)
        }
      }
    }
    if (headerId == "column1" && check == 0) {
      for (var i = 0; i < cr; i++) {
        if (ds_list.getCellData(i, "blNo") != "" && ds_list.getCellData(i, "cntrNo") != "") {
          ds_list.undoRow(i);
        }
      }
    }
  }
};
scwin.gr_list_oncellclick = function (rowIndex, columnIndex, columnId) {
  scwin.updBtnYn = false;
  var vCountRow = ds_list.getRowCount();
  if (vCountRow > 0 && scwin.isBatch == 0) {
    $c.gus.cfEnableBtnOnly($p, [btn_update, btn_updateBatch]);
    if (!scwin.updBtnYn) {
      $c.gus.cfDisableObjects($p, [ica_ed_cntrCrryoutCloseDt, ica_ed_cntrRtrnDt]);
      $c.gus.cfDisableBtnOnly($p, [btn_save]);
    }
  } else {
    $c.gus.cfDisableBtnOnly($p, [btn_update, btn_updateBatch]);
    $c.gus.cfEnableBtnOnly($p, [btn_save]);
  }
  let check = ds_list.getCellData(rowIndex, "chk");
  if (columnId == "chk" && check == 1) {
    if (ds_list.getCellData(rowIndex, "blNo") != "" && ds_list.getCellData(rowIndex, "cntrNo") != "") {
      ds_list.setCellData(rowIndex, "chk", 1);
      //상태를 UPDATE로 변경한다.
      ds_list.modifyRowStatus(rowIndex, "U"); //UPDATE(3)
    } else {
      $c.gus.cfAlertMsg($p, "B/L번호와 컨테이너번호가 존재하지 않아  체크할 수 없습니다.");
      ds_list.undoRow(rowIndex);
    }
  }
  if (columnId == "chk" && check == 0) {
    if (ds_list.getCellData(rowIndex, "blNo") != "" && ds_list.getCellData(rowIndex, "cntrNo") != "") {
      ds_list.undoRow(rowIndex);
    }
  }
};
scwin.ica_ed_cntrCrryoutCloseDt_onchange = function () {
  //반출기한을 수정하였을 때 Org값과 비교하여 변경되었다면 체크박스를 체크한다.
  var val = ds_list.getCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt");
  var orgVal = ds_list.getOriginalCellData(ds_list.getRowPosition(), "cntrCrryoutCloseDt");
  var val2 = ds_list.getCellData(ds_list.getRowPosition(), "cntrRtrnDt");
  var orgVal2 = ds_list.getOriginalCellData(ds_list.getRowPosition(), "cntrRtrnDt");
  //console.log("### ica_ed_cntrCrryoutCloseDt_onchange : "+val+" :: "+orgVal);

  if (val != orgVal || val2 != orgVal2) {
    ds_list.setCellData(ds_list.getRowPosition(), "chk", 1);
  } else {
    ds_list.setCellData(ds_list.getRowPosition(), "chk", 0);
  }
};
